const fs = require('fs');
const FILE = '/data/flagged/study-calendar.ics';

let args;
try { args = typeof query === 'string' ? JSON.parse(query) : query; }
catch { return 'ERROR: expected a JSON object string like {"title":"...","weekday":"monday","start":"09:00","end":"10:30","weeks":12}'; }

const DOW = { sunday:0, monday:1, tuesday:2, wednesday:3, thursday:4, friday:5, saturday:6 };
const title   = String(args.title || 'Study session');
const weekday = String(args.weekday || '').trim().toLowerCase();
const start   = String(args.start || '09:00');
const end     = String(args.end || start);
const weeks   = Number(args.weeks) > 0 ? Number(args.weeks) : 12;
if (!(weekday in DOW)) return `ERROR: weekday must be one of ${Object.keys(DOW).join(', ')}`;

const pad = n => String(n).padStart(2, '0');
const esc = t => String(t).replace(/\\/g,'\\\\').replace(/;/g,'\\;').replace(/,/g,'\\,').replace(/\r?\n/g,'\\n');

const now = new Date();
const delta = (DOW[weekday] - now.getDay() + 7) % 7;
const d = new Date(now.getFullYear(), now.getMonth(), now.getDate() + delta);
const fmt = hhmm => { const [h,m] = String(hhmm).split(':').map(x => parseInt(x,10)||0);
  return `${d.getFullYear()}${pad(d.getMonth()+1)}${pad(d.getDate())}T${pad(h)}${pad(m)}00`; };
const dtstamp = `${now.getUTCFullYear()}${pad(now.getUTCMonth()+1)}${pad(now.getUTCDate())}T${pad(now.getUTCHours())}${pad(now.getUTCMinutes())}${pad(now.getUTCSeconds())}Z`;
const uid = `study-${Date.now()}-${Math.floor(Math.random()*1e6)}@study-planner`;

const vevent = [
  'BEGIN:VEVENT',
  `UID:${uid}`,
  `DTSTAMP:${dtstamp}`,
  `DTSTART:${fmt(start)}`,
  `DTEND:${fmt(end)}`,
  `RRULE:FREQ=WEEKLY;COUNT=${weeks}`,
  `SUMMARY:${esc(title)}`,
  'END:VEVENT'
].join('\r\n');

const HEADER = ['BEGIN:VCALENDAR','VERSION:2.0','PRODID:-//Study Planner//EN','CALSCALE:GREGORIAN','METHOD:PUBLISH'].join('\r\n') + '\r\n';
const FOOTER = 'END:VCALENDAR\r\n';

fs.mkdirSync('/data/flagged', { recursive: true });
let body;
try {
  const existing = fs.readFileSync(FILE, 'utf8');
  body = existing.replace(/END:VCALENDAR\s*$/, '') + vevent + '\r\n' + FOOTER;
} catch {
  body = HEADER + vevent + '\r\n' + FOOTER;
}
fs.writeFileSync(FILE, body);
return `OK: added "${title}" on ${weekday} ${start}-${end}, repeating weekly for ${weeks} weeks.`;
